import { useState, useEffect } from "react";

function StudyWithFriendsPage({ onBack, onLogout }) {
  const [friends, setFriends] = useState(() => [{ id: "me", name: "Ben" }]);
  const [newFriendName, setNewFriendName] = useState("");

  const [status, setStatus] = useState("idle"); // "idle" | "running" | "paused"
  const [elapsedMs, setElapsedMs] = useState(0); // paused/idle için güncel süre
  const [runningSince, setRunningSince] = useState(null); // running için başlangıç zamanı (ms)
  const [now, setNow] = useState(() => Date.now());

  const elapsedNow = (() => {
    if (status === "running" && runningSince) {
      return elapsedMs + (now - runningSince);
    }
    return elapsedMs;
  })();

  const formatTime = (ms) => {
    const totalSeconds = Math.max(0, Math.floor(ms / 1000));
    const mm = String(Math.floor(totalSeconds / 60)).padStart(2, "0");
    const ss = String(totalSeconds % 60).padStart(2, "0");
    return `${mm}:${ss}`;
  };

  useEffect(() => {
    if (status !== "running") return;
    const id = setInterval(() => setNow(Date.now()), 250);
    return () => clearInterval(id);
  }, [status]);

  const handleStart = () => {
    if (status === "running") return;
    setRunningSince(Date.now());
    setStatus("running");
  };

  const handlePause = () => {
    if (status !== "running") return;
    setElapsedMs(elapsedNow);
    setRunningSince(null);
    setStatus("paused");
  };

  const handleFinish = () => {
    setStatus("idle");
    setElapsedMs(0);
    setRunningSince(null);
    setNow(Date.now());
  };

  const handleAddFriend = () => {
    const name = newFriendName.trim();
    if (!name) return;
    setFriends((prev) => {
      if (prev.some((f) => f.name.toLowerCase() === name.toLowerCase())) return prev;
      return [...prev, { id: `${Date.now()}-${Math.random()}`, name }];
    });
    setNewFriendName("");
  };

  const sessionLabel =
    status === "idle" ? "Hazır" : status === "running" ? "Çalışıyor" : "Mola";

  const activeFriends = friends;

  return (
    <div className="container-center">
      <div className="card">
        <div className="topbar">
          <div>
            <div className="subtitle">Canlı çalışma odası</div>
            <h2 className="title" style={{ marginBottom: 0 }}>
              Live Study Room
            </h2>
          </div>
          <button className="btn btn-danger" onClick={onLogout}>
            Çıkış Yap
          </button>
        </div>

        <div className="section-title">Oturum Durumu</div>
        <div className="muted" style={{ marginBottom: 10 }}>
          {sessionLabel} · Süre: <b>{formatTime(elapsedNow)}</b>
        </div>

        <div className="pre" style={{ textAlign: "center", fontSize: 34 }}>
          {formatTime(elapsedNow)}
        </div>

        <div className="actions">
          <button className="btn btn-primary" onClick={handleStart} disabled={status === "running"}>
            Başla
          </button>

          <button className="btn btn-secondary" onClick={handlePause} disabled={status !== "running"}>
            Mola Ver
          </button>

          <button className="btn btn-danger" onClick={handleFinish} disabled={status === "idle"}>
            Çalışmayı Bitir
          </button>
        </div>

        <div className="section-title" style={{ marginTop: 22 }}>
          Arkadaş Ekle
        </div>
        <div className="grid-2" style={{ alignItems: "end" }}>
          <div className="field" style={{ margin: 0 }}>
            <label className="label">İsim</label>
            <input
              className="input"
              placeholder="örn. Ali"
              value={newFriendName}
              onChange={(e) => setNewFriendName(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === "Enter") handleAddFriend();
              }}
            />
          </div>

          <button className="btn btn-primary" onClick={handleAddFriend} disabled={!newFriendName.trim()}>
            Ekle
          </button>
        </div>

        <div className="section-title" style={{ marginTop: 22 }}>
          Çalışanlar Listesi
        </div>
        {activeFriends.length === 0 ? (
          <div className="muted">Henüz kimse yok.</div>
        ) : (
          <div className="stack">
            {activeFriends.map((f) => (
              <div key={f.id} className="select-card">
                <div style={{ display: "flex", justifyContent: "space-between", gap: 10 }}>
                  <div style={{ fontWeight: 900 }}>{f.name}</div>
                  <div className="muted" style={{ fontWeight: 800 }}>
                    {status === "idle" ? "—" : formatTime(elapsedNow)}
                  </div>
                </div>
                <div className="muted" style={{ marginTop: 6 }}>
                  {sessionLabel}
                </div>
              </div>
            ))}
          </div>
        )}

        <div className="actions">
          <button className="btn btn-secondary" onClick={onBack}>
            Geri
          </button>
        </div>
      </div>
    </div>
  );
}

export default StudyWithFriendsPage;
